mapper.select:
SELECT id, username, name, role, dept_id, department, position, employee_id, phone, email, avatar, join_date, created_at, updated_at FROM employees WHERE deleted_at IS NULL
AND ( name LIKE CONCAT('%', #{keyword}, '%') OR employee_id LIKE CONCAT('%', #{keyword}, '%') OR phone LIKE CONCAT('%', #{keyword}, '%') OR username LIKE CONCAT('%', #{keyword}, '%') )
AND department = #{department}
AND role = #{role}
ORDER BY id ASC
